\text{Since } \angle ABC &= 45^\circ, \\
3(5x) &= 45^\circ \\
x &= 3^\circ. \\
\therefore \angle ABD &= 15^\circ. \\
\text{Therefore, } \angle BDE &= 45^\circ - 15^\circ \\
&= \boxed{15^\circ}. \\
\end{align*}



